class Solution:
    def minInterval(self, intervals, queries):
        ans = []
        for q in queries:
            best = -1
            for l, r in intervals:
                if l <= q <= r:
                    size = r - l + 1
                    if best == -1 or size < best:
                        best = size
            ans.append(best)
        return ans

