import heapq
class Solution:
    def minInterval(self, intervals, queries):
        intervals.sort()
        order = sorted(range(len(queries)), key=lambda i: queries[i])
        ans = [-1] * len(queries)
        heap = []
        idx = 0
        n = len(intervals)
        for qi in order:
            q = queries[qi]
            while idx < n and intervals[idx][0] <= q:
                l, r = intervals[idx]
                heapq.heappush(heap, (r - l + 1, r))
                idx += 1
            while heap and heap[0][1] < q:
                heapq.heappop(heap)
            if heap:
                ans[qi] = heap[0][0]
        return ans

