var minInterval = function(intervals, queries) {
    intervals.sort((a, b) => a[0] - b[0]);
    const order = queries.map((q, i) => i).sort((a, b) => queries[a] - queries[b]);
    const ans = new Array(queries.length).fill(-1);
    // min-heap of [size, right]
    const heap = [];
    const up = (i) => {
        while (i > 0) {
            const p = (i - 1) >> 1;
            if (heap[p][0] <= heap[i][0]) break;
            [heap[p], heap[i]] = [heap[i], heap[p]];
            i = p;
        }
    };
    const down = (i) => {
        const n = heap.length;
        while (true) {
            let s = i, l = 2 * i + 1, r = 2 * i + 2;
            if (l < n && heap[l][0] < heap[s][0]) s = l;
            if (r < n && heap[r][0] < heap[s][0]) s = r;
            if (s === i) break;
            [heap[s], heap[i]] = [heap[i], heap[s]];
            i = s;
        }
    };
    const push = (v) => { heap.push(v); up(heap.length - 1); };
    const pop = () => {
        const top = heap[0];
        const last = heap.pop();
        if (heap.length) { heap[0] = last; down(0); }
        return top;
    };
    let idx = 0;
    const n = intervals.length;
    for (const qi of order) {
        const q = queries[qi];
        while (idx < n && intervals[idx][0] <= q) {
            const [l, r] = intervals[idx];
            push([r - l + 1, r]);
            idx++;
        }
        while (heap.length && heap[0][1] < q) pop();
        if (heap.length) ans[qi] = heap[0][0];
    }
    return ans;
};
